const now = new Date();
const d75 = new Date(now); d75.setDate(now.getDate() - 75);
const fmt = d => parseInt(`${d.getFullYear()}${String(d.getMonth()+1).padStart(2,'0')}${String(d.getDate()).padStart(2,'0')}`);
return [{ json: { fecha75: fmt(d75), rango: 2 } }];

